// ============================================================
// EXTRACT TOKEN USAGE - Deep recursive extraction
// Finds ALL LLM token usage from any nesting level
// ============================================================

const executionData = $input.first().json;
const workflowName = executionData.workflowData?.name || 'Unknown Workflow';
const workflowId = executionData.workflowData?.id || 'unknown';
const executionId = executionData.id || 'unknown';
const executionStatus = executionData.status || executionData.finished ? 'success' : 'error';

const llmCalls = [];

function extractTokenUsage(obj, nodeName, nodeType, path, depth) {
  if (!obj || typeof obj !== 'object' || depth > 20) return;

  // Check for token usage patterns
  if (obj.tokenUsage || obj.usage) {
    const usage = obj.tokenUsage || obj.usage;
    const promptTokens = usage.promptTokens || usage.prompt_tokens || usage.input_tokens || 0;
    const completionTokens = usage.completionTokens || usage.completion_tokens || usage.output_tokens || 0;
    const totalTokens = usage.totalTokens || usage.total_tokens || (promptTokens + completionTokens);

    if (totalTokens > 0) {
      const model = obj.model || obj.response?.model || obj.modelName || '';
      const finishReason = obj.finish_reason || obj.response?.choices?.[0]?.finish_reason || obj.finishReason || '';
      const executionTime = obj.executionTime || obj.execution_time || 0;
      const startTime = obj.startTime || obj.start_time || '';

      // Get content preview
      let outputPreview = '';
      try {
        const content = obj.response?.choices?.[0]?.message?.content || obj.text || obj.output || obj.content || '';
        outputPreview = String(content).substring(0, 100);
      } catch(e) {}

      let inputPreview = '';
      try {
        const input = obj.prompt || obj.input || obj.messages?.[0]?.content || '';
        inputPreview = String(input).substring(0, 100);
      } catch(e) {}

      // Get model parameters
      const temperature = obj.temperature ?? obj.options?.temperature ?? null;
      const maxTokens = obj.maxTokens || obj.max_tokens || obj.options?.maxTokens || null;
      const timeout = obj.timeout || obj.options?.timeout || null;
      const retryCount = obj.retryCount || obj.options?.retryCount || null;

      llmCalls.push({
        model: model,
        nodeName: nodeName,
        nodeType: nodeType,
        promptTokens: promptTokens,
        completionTokens: completionTokens,
        totalTokens: totalTokens,
        finishReason: finishReason,
        executionTime: executionTime,
        startTime: startTime,
        outputPreview: outputPreview,
        inputPreview: inputPreview,
        temperature: temperature,
        maxTokens: maxTokens,
        timeout: timeout,
        retryCount: retryCount,
        path: path,
        workflowName: workflowName,
        workflowId: workflowId,
        executionId: executionId,
        executionStatus: executionStatus
      });
      return; // Don't recurse further into this branch
    }
  }

  // Recurse into arrays and objects
  if (Array.isArray(obj)) {
    obj.forEach((item, i) => extractTokenUsage(item, nodeName, nodeType, `${path}[${i}]`, depth + 1));
  } else {
    for (const key of Object.keys(obj)) {
      if (key === 'binary' || key === 'pairedItem') continue;
      extractTokenUsage(obj[key], nodeName, nodeType, `${path}.${key}`, depth + 1);
    }
  }
}

// Process all nodes in the execution
const runData = executionData.data?.resultData?.runData || {};

for (const [nodeName, nodeRuns] of Object.entries(runData)) {
  if (!Array.isArray(nodeRuns)) continue;

  for (const run of nodeRuns) {
    const nodeType = run.source?.[0]?.previousNode || '';
    const actualNodeType = executionData.workflowData?.nodes?.find(n => n.name === nodeName)?.type || '';

    // Search in main data
    if (run.data?.main) {
      for (const outputSet of run.data.main) {
        if (!outputSet) continue;
        for (const item of outputSet) {
          extractTokenUsage(item.json || item, nodeName, actualNodeType, nodeName, 0);
        }
      }
    }

    // Search in inputOverride (for sub-nodes like LLM chains)
    if (run.inputOverride) {
      extractTokenUsage(run.inputOverride, nodeName, actualNodeType, `${nodeName}.inputOverride`, 0);
    }
  }
}

if (llmCalls.length === 0) {
  return [{ json: { error: 'No LLM calls detected in this execution', workflowName, executionId, executionStatus } }];
}

return llmCalls.map(call => ({ json: call }));

// ============================================================
// FIND NODES WITH LLM DATA - Identifies all LLM-related nodes
// Provides node-level metadata for analytics
// ============================================================

const executionData = $input.first().json;
const workflowNodes = executionData.workflowData?.nodes || [];
const runData = executionData.data?.resultData?.runData || {};
const connections = executionData.workflowData?.connections || {};

const llmNodeTypes = [
  '@n8n/n8n-nodes-langchain.lmChatOpenAi',
  '@n8n/n8n-nodes-langchain.lmChatAnthropic',
  '@n8n/n8n-nodes-langchain.lmChatGoogleGemini',
  '@n8n/n8n-nodes-langchain.lmChatOllama',
  '@n8n/n8n-nodes-langchain.lmChatAzureOpenAi',
  '@n8n/n8n-nodes-langchain.lmChatMistralCloud',
  '@n8n/n8n-nodes-langchain.lmChatGroq',
  '@n8n/n8n-nodes-langchain.lmChatDeepSeek',
  '@n8n/n8n-nodes-langchain.lmChatHuggingFace',
  '@n8n/n8n-nodes-langchain.lmChatAwsBedrock',
  '@n8n/n8n-nodes-langchain.agent',
  '@n8n/n8n-nodes-langchain.chainLlm',
  '@n8n/n8n-nodes-langchain.chainSummarization',
  '@n8n/n8n-nodes-langchain.chainRetrievalQa',
  '@n8n/n8n-nodes-langchain.openAi',
  'n8n-nodes-base.openAi'
];

const nodeDetails = [];

for (const node of workflowNodes) {
  const isLLMNode = llmNodeTypes.some(t => node.type?.includes(t)) || 
                    node.type?.toLowerCase().includes('llm') ||
                    node.type?.toLowerCase().includes('openai') ||
                    node.type?.toLowerCase().includes('anthropic') ||
                    node.type?.toLowerCase().includes('gemini') ||
                    node.type?.toLowerCase().includes('agent');

  if (isLLMNode || runData[node.name]) {
    // Find previous nodes chain
    const prevNodes = [];
    function findPrevious(nodeName, depth) {
      if (depth > 10) return;
      for (const [connName, connData] of Object.entries(connections)) {
        if (!connData.main) continue;
        for (const outputs of connData.main) {
          if (!outputs) continue;
          for (const conn of outputs) {
            if (conn.node === nodeName) {
              prevNodes.push(connName);
              findPrevious(connName, depth + 1);
            }
          }
        }
      }
    }
    findPrevious(node.name, 0);

    const nodeRun = runData[node.name];
    const executionTime = nodeRun?.[0]?.executionTime || 0;
    const startTime = nodeRun?.[0]?.startTime || '';

    nodeDetails.push({
      nodeName: node.name,
      nodeType: node.type,
      isLLMNode: isLLMNode,
      executionTime: executionTime,
      startTime: startTime,
      previousNodes: prevNodes.reverse().join(' → '),
      position: node.position
    });
  }
}

return nodeDetails.map(d => ({ json: d }));

// ============================================================
// STOP AND ERROR - Unknown model detected
// Lists all unknown models so user can add them
// ============================================================

const items = $input.all();
const unknownModels = items
  .filter(item => !item.json.modelKnown)
  .map(item => item.json.rawModel);

const uniqueUnknown = [...new Set(unknownModels)];

throw new Error(
  `Unknown model(s) detected: ${uniqueUnknown.join(', ')}\n\n` +
  `Please add these models to:\n` +
  `1. The "Standardize Names" node (standardize_names_dic)\n` +
  `2. The "Model Prices" node (MODEL_PRICES)\n\n` +
