  const model = data.standardizedModel || 'unknown';
  const pricing = MODEL_PRICES[model];

  if (pricing) {
    data.promptCost = (data.promptTokens / 1000000) * pricing.input;
    data.completionCost = (data.completionTokens / 1000000) * pricing.output;
    data.totalCost = data.promptCost + data.completionCost;
    data.inputPricePerM = pricing.input;
    data.outputPricePerM = pricing.output;
    data.pricingFound = true;
  } else {
    // Fallback pricing for truly unknown models
    data.promptCost = (data.promptTokens / 1000000) * 1.00;
    data.completionCost = (data.completionTokens / 1000000) * 3.00;
    data.totalCost = data.promptCost + data.completionCost;
    data.inputPricePerM = 1.00;
    data.outputPricePerM = 3.00;
    data.pricingFound = false;
  }

  // Round to 6 decimal places
  data.promptCost = Math.round(data.promptCost * 1000000) / 1000000;
  data.completionCost = Math.round(data.completionCost * 1000000) / 1000000;
  data.totalCost = Math.round(data.totalCost * 1000000) / 1000000;

  return { json: data };
});

return results;

// ============================================================
// GENERATE SUMMARY - Comprehensive analytics output
// Produces per-call details + aggregated summary statistics
// ============================================================

const items = $input.all();

if (items.length === 0) {
  return [{ json: { error: 'No data to summarize' } }];
}

const details = items.map(item => item.json);

// Calculate summary statistics
let totalCost = 0;
let totalPromptTokens = 0;
let totalCompletionTokens = 0;
let totalTokens = 0;
let totalExecutionTime = 0;
const modelBreakdown = {};
const nodeBreakdown = {};

for (const call of details) {
  totalCost += call.totalCost || 0;
  totalPromptTokens += call.promptTokens || 0;
  totalCompletionTokens += call.completionTokens || 0;
  totalTokens += call.totalTokens || 0;
  totalExecutionTime += call.executionTime || 0;

  // Model breakdown
  const model = call.standardizedModel || 'unknown';
  if (!modelBreakdown[model]) {
    modelBreakdown[model] = { calls: 0, cost: 0, promptTokens: 0, completionTokens: 0, totalTokens: 0 };
  }
  modelBreakdown[model].calls++;
  modelBreakdown[model].cost += call.totalCost || 0;
  modelBreakdown[model].promptTokens += call.promptTokens || 0;
  modelBreakdown[model].completionTokens += call.completionTokens || 0;
  modelBreakdown[model].totalTokens += call.totalTokens || 0;

  // Node breakdown
  const node = call.nodeName || 'unknown';
  if (!nodeBreakdown[node]) {
    nodeBreakdown[node] = { calls: 0, cost: 0, model: model, promptTokens: 0, completionTokens: 0 };
  }
  nodeBreakdown[node].calls++;
  nodeBreakdown[node].cost += call.totalCost || 0;
  nodeBreakdown[node].promptTokens += call.promptTokens || 0;
  nodeBreakdown[node].completionTokens += call.completionTokens || 0;
}

// Round summary values
for (const m of Object.values(modelBreakdown)) {
  m.cost = Math.round(m.cost * 1000000) / 1000000;
}
for (const n of Object.values(nodeBreakdown)) {
  n.cost = Math.round(n.cost * 1000000) / 1000000;
}

const summary = {
  workflowName: details[0]?.workflowName || 'Unknown',
  workflowId: details[0]?.workflowId || 'unknown',
  executionId: details[0]?.executionId || 'unknown',
  executionStatus: details[0]?.executionStatus || 'unknown',
  totalLLMCalls: details.length,
  totalCost: Math.round(totalCost * 1000000) / 1000000,
  totalPromptTokens: totalPromptTokens,
  totalCompletionTokens: totalCompletionTokens,
  totalTokens: totalTokens,
  averageCostPerCall: Math.round((totalCost / details.length) * 1000000) / 1000000,
  totalExecutionTimeMs: totalExecutionTime,
  modelBreakdown: modelBreakdown,
  nodeBreakdown: nodeBreakdown,
  timestamp: new Date().toISOString()
};

return [{ json: { summary: summary, details: details } }];
